/**
 * Greets a person by their first and last name.
 * @param {Object} options - The person's name options.
 * @param {string} [options.firstname] - The person's first name.
 * @param {string} [options.lastname] - The person's last name.
 * @returns {string} A greeting message.
 */
export function sayHi(options) {
  const { firstname, lastname } = options;
  let message = ["Hello"];
  if (firstname) {
    message.push(firstname);
  }
  if (lastname) {
    message.push(lastname);
  }
  return message.join(", ");
}

/**
 * Adds two numbers together.
 * @param {number} a - The first number.
 * @param {number} b - The second number.
 * @returns {number} The sum of a and b.
 */
export function add(...numbers) {
  return numbers.reduce((sum, num) => sum + num, 0);
}

/**
 * Subtracts the second number from the first number.
 * @param {number} a - The first number.
 * @param {number} b - The second number.
 * @returns {number} The difference of a and b.
 */
export function subtract(a, b) {
  return a - b;
}

/**
 * Multiplies two numbers together.
 * @param {number} a - The first number.
 * @param {number} b - The second number.
 * @returns {number} The product of a and b.
 */
export function multiply(a, b) {
  return a * b;
}

export function lerp(params) {
  const { start, end, t, roundUp = false } = params;
  const result = [];

  for (let i = 0; i < start.length; i++) {
    const value = start[i] + t * (end[i] - start[i]);
    result.push(roundUp ? Math.ceil(value) : value);
  }

  return result;
}

/**
 * Divides the first number by the second number.
 * @param {number} a - The first number.
 * @param {number} b - The second number.
 * @returns {number} The quotient of a and b.
 * @throws {Error} If b is zero.
 */
export function divide(a, b) {
  if (b === 0) {
    throw new Error("Cannot divide by zero");
  }
  return a / b;
}

