console.log(subtract(5, 3), subtract(10, 7), subtract(8, 2));
console.log(multiply(3, 4), multiply(5, 6), multiply(7, 8));
console.log(divide(10, 2), divide(15, 3), divide(20, 4));
console.log(lerp({ start: [0, 0], end: [10, 20], t: 0.5 }));
console.log(lerp({ start: [1, 2, 3], end: [4, 5, 6], t: 0.25, roundUp: true }));
console.log(lerp({ start: [0, 0], end: [1, 1], t: 0.75 }));
console.log(lerp({ start: [10, 20], end: [0, 0], t: 0.5, roundUp: true }));
